import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"21. Casual Conversion","description":"","frontmatter":{"title":"21. Casual Conversion","eba":"Biomedical Engineers 2025-2028","topics":["employment","casual-conversion"]},"headers":[],"relativePath":"ebas/biomedical-engineers/employment/21-casual-conversion.md","filePath":"ebas/biomedical-engineers/employment/21-casual-conversion.md"}'),n={name:"ebas/biomedical-engineers/employment/21-casual-conversion.md"};function i(a,e,p,l,h,u){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_21-casual-conversion" tabindex="-1">21. Casual Conversion <a class="header-anchor" href="#_21-casual-conversion" aria-label="Permalink to &quot;21. Casual Conversion&quot;">​</a></h1><p><strong>21.1</strong> Employee Requests</p><p><strong>(a)</strong> A casual Employee may make a request to convert to permanent employment under this clause 21 if:</p><p><strong>(i)</strong> the Employee has been employed by the Employer for a period of at least 6 months beginning the day the employment started;</p><p><strong>(ii)</strong> the Employee has, in the period of 6 months ending the day the request is given, worked a regular pattern of hours on an ongoing basis which, without significant adjustment, the employee could continue to work as a full-time Employee or a part-time Employee (as the case may be); and</p><p><strong>(iii)</strong> all of the following apply: <strong>(A)</strong> the Employee has not, at any time during the period referred to in subclause 21.1(a)(ii), refused an offer for casual conversion made to the Employee; <strong>(B)</strong> the Employer has not, at any time during that period, given the Employee a notice in accordance with subclause 21.4(a); <strong>(C)</strong> the Employer has not, at any time during that period, given a response to the Employee under clause 21.2 refusing a previous request made under this clause; <strong>(D)</strong> the request is not made during the period of 21 days after the period referred to in subclause 21.1(a)(i).</p><p><strong>(b)</strong> The request to convert to permanent employment under clause 21.1(a) must:</p><p><strong>(i)</strong> be provided to the Employer in writing; and</p><p><strong>(ii)</strong> be a request for the Employee to convert: <strong>(A)</strong> for an Employee that has worked the equivalent of full-time hours or shifts on a regular and systematic basis during the period referred to in subclause 21.1(a)(ii) – to full-time employment; or <strong>(B)</strong> for an Employee that has worked less than the equivalent of full-time hours or shifts on a regular and systematic basis during the period referred to in subclause 21.1(a)(ii) – to part-time employment that is consistent with the regular pattern of hours or shifts worked during that period.</p><p><strong>21.2</strong> Employer must give a response The Employer must provide a written response to the request within 21 days after the request is received, either granting or refusing the conversion.</p><p><strong>21.3</strong> Refusals of requests</p><p><strong>(a)</strong> The Employer must not refuse the request unless:</p><p><strong>(i)</strong> the Employer has consulted the Employee;</p><p><strong>(ii)</strong> there are reasonable grounds the refuse the request; and</p><p><strong>(iii)</strong> the reasonable grounds are based on facts that are known, or reasonably foreseeable, at the time of refusing the request.</p><p><strong>(b)</strong> Without limiting subclause 21.3(a), reasonable grounds for refusing a request include the following:</p><p><strong>(i)</strong> it would require a significant adjustment to the Employee’s hours of work in order for the Employee to be employed as a full-time Employee or part-time Employee;</p><p><strong>(ii)</strong> the Employee’s position will cease to exist in the period of 12 months after giving the request;</p><p><strong>(iii)</strong> the hours of work which the Employee is required to perform will be significantly reduced in the period of 12 months after giving the request;</p><p><strong>(iv)</strong> there will be a significant change in either or both of the following in the period of 12 months after giving the request: <strong>(A)</strong> the days on which the Employee’s hours of work are required to be performed; <strong>(B)</strong> the times at which the Employee’s hours of work are required to be performed; which cannot be accommodated within the days or times the Employee is available to work during that period; and</p><p><strong>(v)</strong> granting the request would not comply with a recruitment or selection process required by or under a law of the Commonwealth or a State or a Territory.</p><p><strong>(c)</strong> If the Employer refuses the request, the written response under clause 21.2 must include details of the reasons for the refusal.</p><p><strong>21.4</strong> Grants of requests</p><p><strong>(a)</strong> If the Employer grants the request, the Employer must, within 21 days after the day the request is given to the Employer, give written notice to the Employee of the following:</p><p><strong>(i)</strong> whether the Employee is converting to full-time employment or part-time employment;</p><p><strong>(ii)</strong> the Employee&#39;s pattern of hours or shifts after the conversion takes effect; and</p><p><strong>(iii)</strong> the day the Employee&#39;s conversion to full-time or part-time employment takes effect.</p><p><strong>(b)</strong> However, the Employer must discuss with the Employee the matters the Employer intends to specify for the purposes of subclause 21.4(a)(i)-(iii) before giving the notice.</p><p><strong>(c)</strong> The day specified for the purposes of subclause 21.4(a)(iii) must be the first day of the Employee&#39;s first full pay period that starts after the day the notice is given, unless the Employee and Employer agree to another day.</p><p><strong>(d)</strong> To avoid doubt, the notice may be included in the written response under clause 21.2.</p><p><strong>21.5</strong> Effect of conversion</p><p><strong>(a)</strong> An Employee is taken, on and after the day specified in a notice for the purposes of subclause 21.4(a)(iii), to be a full-time Employee or a part-time Employee of the Employer.</p><p><strong>(b)</strong> Casual loading will cease, and, subject to this Agreement, any benefits relating to permanent employment will commence on the day specified in a notice for the purposes of subclause 21.4(a)(iii).</p><p>Plain language terms: casual to permanent.</p>',34)])])}const d=t(n,[["render",i]]);export{g as __pageData,d as default};
